// src/optimizer.ts

export class TokenOptimizer {
    /**
     * Velmi rychlý odhad počtu tokenů (1 token ≈ 4 znaky anglického textu/kódu)
     * V produkci by se nahradilo přesným tokenizerem (např. tiktoken)
     */
    static estimateTokens(text: string): number {
        return Math.ceil(text.length / 4);
    }

    /**
     * Vypočítá odhadovanou cenu požadavku podle ceníku Anthropic
     * Ceny jsou v USD za 1000 vstupních tokenů
     */
    static calculateCost(tokens: number, model: 'claude-3-haiku' | 'claude-3.5-sonnet'): number {
        const pricing = {
            'claude-3-haiku': 0.00025,
            'claude-3.5-sonnet': 0.003
        };
        
        return (tokens / 1000) * pricing[model];
    }

    /**
     * Context Pruner: Vyfiltruje zbytečné soubory (node_modules, build soubory atd.),
     * aby se do AI neposílal balast.
     */
    static pruneContext(filePaths: string[], ignorePatterns: string[] = ['.git', 'node_modules', 'dist', 'build']): string[] {
        return filePaths.filter(file => {
            return !ignorePatterns.some(pattern => file.includes(pattern));
        });
    }
}

// --- UKÁZKA POUŽITÍ (Testovací skript) ---
const mockCodeSnippet = `
    function helloWorld() {
        console.log("Optimalizujeme kredity!");
        for(let i = 0; i < 1000; i++) {
            // nejaka tezka logika
        }
    }
`;

console.log("=== Antigravity Token Optimizer ===");

const estimatedTokens = TokenOptimizer.estimateTokens(mockCodeSnippet);
const estimatedCost = TokenOptimizer.calculateCost(estimatedTokens, 'claude-3.5-sonnet');

console.log(`Analyzovaný kód má odhadem: ${estimatedTokens} tokenů.`);
console.log(`Odhadovaná cena pro Claude 3.5 Sonnet: $${estimatedCost.toFixed(6)}`);

const filesToSend = ['src/main.ts', 'node_modules/react/index.js', 'package.json', '.git/config'];
const cleanedFiles = TokenOptimizer.pruneContext(filesToSend);
console.log(`\nSoubory po pročištění kontextu:`, cleanedFiles);